          .attr('font-family','Arial,sans-serif')
          .attr('fill','black')
          .text(y);
      }

      svgSel.append('line')
        .attr('x1',X(xMin))
        .attr('y1',Y(0))
        .attr('x2',X(xMax))
        .attr('y2',Y(0))
        .attr('stroke',AXIS)
        .attr('stroke-width',1.4);

      svgSel.append('line')
        .attr('x1',X(0))
        .attr('y1',Y(yMin))
        .attr('x2',X(0))
        .attr('y2',Y(yMax))
        .attr('stroke',AXIS)
        .attr('stroke-width',1.4);

      svgSel.append('text')
        .attr('x',X(xMax)-3)
        .attr('y',Y(0)-6)
        .attr('text-anchor','end')
        .attr('font-size',13)
        .attr('font-family','Arial,sans-serif')
        .attr('font-weight','bold')
        .attr('fill','black')
        .text('x');

      svgSel.append('text')
        .attr('x',X(0)+7)
        .attr('y',Y(yMax)+14)
        .attr('font-size',13)
        .attr('font-family','Arial,sans-serif')
        .attr('font-weight','bold')
        .attr('fill','black')
        .text('y');
    }

    function redraw() {
      const value=+inp.value;
      const M=matrixFromValue(value);
      const transformed=square.map(p=&gt;apply(M,p));

      const svgSel=d3.select(svg);
      svgSel.selectAll('*').remove();

      drawAxes(svgSel);

      svgSel.append('path')
        .attr('d',pathFor(square))
        .attr('fill','none')
        .attr('stroke',ORIGINAL)
        .attr('stroke-width',1.4)
        .attr('stroke-dasharray','4 3');

      svgSel.append('path')
        .attr('d',pathFor(transformed))
        .attr('fill',SHAPE_FILL)
        .attr('stroke',SHAPE)
        .attr('stroke-width',2.2);

      svgSel.selectAll('.corner')
        .data(transformed)
        .join('circle')
        .attr('class','corner')
        .attr('cx',d=&gt;X(d[0]))
        .attr('cy',d=&gt;Y(d[1]))
        .attr('r',3)
        .attr('fill',SHAPE);

      readout.textContent=`${sliderLabel}: ${valueText(value)}`;
    }

    inp.addEventListener('input',redraw);
    redraw();

    return wrap;
  }

  const rotationPanel=makePanel(
    'rotation',
    'angle',
    0,90,1,0,
    value=&gt;R(value),
    value=&gt;`${value.toFixed(0)}°`
  );

  const shearPanel=makePanel(
    'shear',
    'shear',
    0,1,0.01,0,
    value=&gt;shear(value),
    value=&gt;value.toFixed(2)
  );

  const stretchPanel=makePanel(
    'squish/stretch',
    'stretch factor',
    1,2,0.01,1,
    value=&gt;stretch(value),
    value=&gt;`${value.toFixed(2)} × ${(+1/value).toFixed(2)}`
  );

  const allPanel=makePanel(
    'all three together',
    'amount',
    0,1,0.01,0,
    value=&gt;{
      const theta=90*value;
      const s=value;
      const lambda=1+value;
      return mul(R(theta),mul(shear(s),stretch(lambda)));
    },
    value=&gt;value.toFixed(2)
  );

  const container=document.createElement('div');
  container.style.cssText=
    `background:${BG};padding:10px;display:grid;grid-template-columns:${panelW}px ${panelW}px;`+
    `gap:12px;width:${2*panelW+12+20}px;box-sizing:border-box;`;

  container.append(rotationPanel,shearPanel,stretchPanel,allPanel);

  return container;
}
